+constexpr int32_t CCONV_DBG_SEQ = -1;
+constexpr int32_t CCONV_DBG_C0 = -1;
+constexpr int32_t CCONV_DBG_MAX_TOKENS = 0;
+constexpr int32_t CCONV_DBG_VERBOSE_TOKENS = 0;
+constexpr int32_t CCONV_DBG_DUMP_SIZE = 0;
